function Invoke-GitChecked {
  & git @args
  if ($LASTEXITCODE -ne 0) { throw "git $($args -join ' ') failed" }
}

function Test-GitDirty {
  $dirty = & git status --porcelain
  if ($LASTEXITCODE -ne 0) { throw "git status failed" }
  if ($null -eq $dirty) { return $false }
  return @($dirty).Count -gt 0
}

function Update-GitMain {
  param([string]$RemoteName, [string]$MainBranch)

  & git fetch $RemoteName $MainBranch
  if ($LASTEXITCODE -ne 0) { throw "Could not fetch $RemoteName/$MainBranch." }
  & git show-ref --verify --quiet "refs/remotes/$RemoteName/$MainBranch" *> $null
  if ($LASTEXITCODE -ne 0) { throw "Remote $RemoteName/$MainBranch was not found." }
  Invoke-GitChecked switch $MainBranch
  & git merge --ff-only "$RemoteName/$MainBranch"
  if ($LASTEXITCODE -ne 0) {
    throw "main cannot be fast-forwarded from $RemoteName/$MainBranch. Resolve main manually, then retry."
  }
}

function Restore-GitStash {
  $stashRef = 'stash@{0}'
  try {
    Invoke-GitChecked stash apply $stashRef
    Invoke-GitChecked stash drop $stashRef
  } catch {
    Write-Error "Stash restore stopped. Resolve conflicts before continuing; the stash was kept as $stashRef."
    throw
  }
}

function Invoke-GitNewBranch {
  $rawBranchName = @'
{{branch_name}}
'@
  $branchName = $rawBranchName.Trim()
  if ([string]::IsNullOrWhiteSpace($branchName)) { throw "Branch name is required." }
  if ($branchName.Contains("`n") -or $branchName.Contains("`r")) { throw "Branch name must be a single line." }
  if ($branchName.StartsWith("-")) { throw "Branch name must not start with '-'." }

  & git rev-parse --git-dir *> $null
  if ($LASTEXITCODE -ne 0) { throw "Not in a Git repository." }

  $validatedBranchName = & git check-ref-format --branch $branchName
  if ($LASTEXITCODE -ne 0) { throw "Invalid branch name: $branchName" }
  $validatedBranchName = ($validatedBranchName -join "").Trim()
  if ($validatedBranchName -ne $branchName) { throw "Branch name must be explicit and unambiguous." }

  & git show-ref --verify --quiet "refs/heads/$branchName"
  if ($LASTEXITCODE -eq 0) { throw "Branch '$branchName' already exists." }
  if ($LASTEXITCODE -ne 1) { throw "git show-ref failed" }

  $mainBranch = "main"
  $remoteName = "origin"
  $currentBranch = (& git branch --show-current).Trim()
  if ($LASTEXITCODE -ne 0 -or [string]::IsNullOrWhiteSpace($currentBranch)) { throw "Not on a branch." }

  if ($currentBranch -eq $mainBranch) {
    if (Test-GitDirty) {
      Write-Host "Local changes are on main; creating $branchName before updating main."
      Invoke-GitChecked switch -c $branchName
      $stashed = $false
      if (Test-GitDirty) {
        Invoke-GitChecked stash push -u -m "branch $branchName from main"
        $stashed = $true
      }
      try {
        Update-GitMain -RemoteName $remoteName -MainBranch $mainBranch
      } catch {
        & git switch $branchName *> $null
        if ($stashed) { Write-Error "Local work is preserved in stash@{0}." }
        throw
      }
      Invoke-GitChecked switch $branchName
      try {
        Invoke-GitChecked rebase $mainBranch
      } catch {
        Write-Error "Rebase stopped. Resolve conflicts, then run git rebase --continue or git rebase --abort."
        if ($stashed) { Write-Error "Local work is preserved in stash@{0}; apply it after finishing or aborting the rebase." }
        throw
      }
      if ($stashed) {
        Restore-GitStash
      }
    } else {
      Update-GitMain -RemoteName $remoteName -MainBranch $mainBranch
      Invoke-GitChecked switch -c $branchName
    }
  } else {
    Invoke-GitChecked switch -c $branchName
  }

  Invoke-GitChecked status --short
}

Invoke-GitNewBranch
